#!/bin/bash
# install.sh — Amazon Signal Map Skills Installer
# Usage: bash install.sh
# Downloads and installs both Claude Code skills to ~/.claude/skills/

set -e

echo "============================================="
echo " Amazon Signal Map Skills — Installer v2"
echo "============================================="
echo ""

# Check prerequisites
if ! command -v python3 &>/dev/null; then
  echo "ERROR: python3 is required for installation."
  echo "Install Python 3 (it ships with macOS) and retry."
  exit 1
fi

SKILLS_DIR="$HOME/.claude/skills"

echo "Installing to: $SKILLS_DIR"
echo ""

# Create directory structure
mkdir -p "$SKILLS_DIR/amazon-data-export-intelligence"
mkdir -p "$SKILLS_DIR/seller-intelligence-packager"
mkdir -p "$SKILLS_DIR/amazon-signal-map/scripts"

# Install all files via embedded base64
python3 << 'PYEOF'
import base64, os, stat

SKILLS_DIR = os.path.expanduser("~/.claude/skills")

FILES = {
    os.path.join(SKILLS_DIR, "amazon-data-export-intelligence", "SKILL.md"): (
        ""
        , False
    ),
    os.path.join(SKILLS_DIR, "seller-intelligence-packager", "SKILL.md"): (
        ""
        , False
    ),
    os.path.join(SKILLS_DIR, "amazon-signal-map", "CLAUDE.md"): (
        ""
        , False
    ),
    os.path.join(SKILLS_DIR, "amazon-signal-map", "amazon-export-field-reference.md"): (
        ""
        , False
    ),
    os.path.join(SKILLS_DIR, "amazon-signal-map", "scripts", "inspect-archive.sh"): (
        ""
        , True
    ),
    os.path.join(SKILLS_DIR, "amazon-signal-map", "scripts", "sample-csv.sh"): (
        ""
        , True
    ),
}

print("Writing files...")
for path, (b64data, is_exec) in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64data))
    if is_exec:
        current = os.stat(path).st_mode
        os.chmod(path, current | stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)
    print(f"  OK  {path}")

print()
print("All files written successfully.")
PYEOF

echo ""
echo "============================================="
echo " INSTALL COMPLETE"
echo "============================================="
echo ""
echo "Skills installed to: $SKILLS_DIR"
echo ""
echo "Installed:"
echo "  - amazon-data-export-intelligence/SKILL.md"
echo "  - seller-intelligence-packager/SKILL.md"
echo "  - amazon-signal-map/CLAUDE.md (workspace config)"
echo "  - amazon-signal-map/amazon-export-field-reference.md"
echo "  - amazon-signal-map/scripts/inspect-archive.sh"
echo "  - amazon-signal-map/scripts/sample-csv.sh"
echo ""
echo "Usage in Claude Code:"
echo "  /amazon-data-export-intelligence   (when you have a ZIP export)"
echo "  /seller-intelligence-packager      (to package completed analysis)"
echo ""
echo "Or just describe what you want — Claude will pick the right skill."
echo ""
echo "Next: open Claude Code in the folder where your Amazon export lives"
echo "      and say: 'I just downloaded my Amazon data export. Let's analyze it.'"
echo ""
